window.HK2_LC2 = {"q12": [{"n": 1, "part": 1, "q": "", "qko": "", "opts": ["He's facing a closed window.", "He's painting a portion of the wall.", "He's repositioning a stepladder.", "He's extending his arms upward."], "optko": ["그는 닫혀 있는 창문을 향해 있다.", "그는 벽의 일부를 페인트칠하고 있다.", "그는 발판 사다리를 옮기고 있다.", "그는 위쪽을 향해 팔을 뻗고 있다."], "ans": 3, "audio": "Test02_01.mp3", "img": "hk2_t2_q1.jpg"}, {"n": 2, "part": 1, "q": "", "qko": "", "opts": ["One of the women is cleaning a counter.", "One of the women is filling plates with cupcakes.", "One of the women is lifting a cup.", "One of the women is taking baked goods out of a kitchen."], "optko": ["여자들 중 한 명이 조리대를 닦고 있다.", "여자들 중 한 명이 접시들을 컵케이크로 채우고 있다.", "여자들 중 한 명이 컵을 들어 올리고 있다.", "여자들 중 한 명이 제과들을 주방 밖으로 내놓고 있다."], "ans": 2, "audio": "Test02_02.mp3", "img": "hk2_t2_q2.jpg"}, {"n": 3, "part": 1, "q": "", "qko": "", "opts": ["A woman has her hand on a computer.", "They're studying X-ray images.", "A man is turning on a screen.", "Some people are filing a document."], "optko": ["한 여자가 자신의 손을 컴퓨터 위에 올려놓고 있다.", "그들은 엑스레이 사진들을 검토하고 있다.", "한 남자가 화면을 켜고 있다.", "몇몇 사람들이 문서를 철하고 있다."], "ans": 1, "audio": "Test02_03.mp3", "img": "hk2_t2_q3.jpg"}, {"n": 4, "part": 1, "q": "", "qko": "", "opts": ["She's paying for some jewelry at a checkout.", "She's trying on a necklace in a boutique.", "She's carrying a handbag on her shoulder.", "She's assembling one of the store shelves."], "optko": ["그녀는 계산대에서 몇몇 장신구들의 비용을 지불하고 있다.", "그녀는 부티크에서 목걸이를 착용해보고 있다.", "그녀는 핸드백을 어깨에 메고 있다.", "그녀는 가게 선반들 중 하나를 조립하고 있다."], "ans": 2, "audio": "Test02_04.mp3", "img": "hk2_t2_q4.jpg"}, {"n": 5, "part": 1, "q": "", "qko": "", "opts": ["Umbrellas have been unfolded above the tables.", "A cruise ship has stopped in the harbor.", "A set of patio furniture is being placed on a vessel.", "Streetlamps circle an outdoor dining area."], "optko": ["파라솔들이 테이블 위에 펼쳐져 있다.", "여객선이 항구에 멈춰 서 있다.", "테라스용 가구가 배 위에 놓이고 있다.", "가로등들이 야외 식사 공간을 둥글게 둘러싸고 있다."], "ans": 1, "audio": "Test02_05.mp3", "img": "hk2_t2_q5.jpg"}, {"n": 6, "part": 1, "q": "", "qko": "", "opts": ["A statue has been situated in a plaza.", "A group of people is sitting on the steps.", "A structure is being reflected in a window.", "A building is being constructed by a work crew."], "optko": ["조각상이 광장에 위치해 있다.", "한 무리의 사람들이 계단에 앉아 있다.", "구조물이 창문에 비치고 있다.", "건물이 인부들에 의해 건설되고 있다."], "ans": 0, "audio": "Test02_06.mp3", "img": "hk2_t2_q6.jpg"}, {"n": 7, "part": 2, "q": "How many people are we expecting for our performances on Sunday?", "qko": "우리는 일요일 공연에 몇 명의 사람들을 예상하고 있나요?", "opts": ["100 for each show.", "They'll be here at 8.", "We've performed it many times."], "optko": ["각 공연당 100명이요.", "그들은 8시에 여기 올 거예요.", "우리는 그것을 여러 번 공연했어요."], "ans": 0, "audio": "Test02_07.mp3"}, {"n": 8, "part": 2, "q": "Brad, can you set up the dining room for a dinner?", "qko": "Brad, 저녁 식사를 위해 식당을 준비해 주실 수 있나요?", "opts": ["Yes, it was delicious.", "Not particularly.", "Sure, in a bit."], "optko": ["네, 그것은 맛있었어요.", "특별히 없어요.", "물론이죠, 잠시 후에요."], "ans": 2, "audio": "Test02_08.mp3"}, {"n": 9, "part": 2, "q": "Who moved the boxes from the front door?", "qko": "누가 정문에 있는 상자들을 옮겼나요?", "opts": ["I'm sure it's in the back room.", "I'll do it right after the snow stops.", "I saw Issac doing it this morning."], "optko": ["뒤쪽 방에 있다고 확신해요.", "눈이 그치고 나면 제가 바로 할게요.", "오늘 아침에 Issac이 하는 걸 봤어요."], "ans": 2, "audio": "Test02_09.mp3"}, {"n": 10, "part": 2, "q": "My medical checkup is at 4:40, but I won't finish work until 5 today.", "qko": "제 건강 검진이 4시 40분인데, 오늘 저는 5시나 되어야 일이 끝날 거예요.", "opts": ["At Queens Hospital.", "That's a problem.", "You need to make sure you're qualified."], "optko": ["Queens 병원에서요.", "그거 문제네요.", "당신이 자격이 있는지를 확실히 해야 해요."], "ans": 1, "audio": "Test02_10.mp3"}, {"n": 11, "part": 2, "q": "Would you prefer to rent a sedan or a larger vehicle?", "qko": "세단을 대여하는 것이 좋으세요, 아니면 더 큰 차량을 대여하는 것이 좋으세요?", "opts": ["I've run out of gas.", "The rental fee is negotiable.", "We require a van to fit everyone."], "optko": ["기름이 다 떨어졌어요.", "대여 비용은 협의 가능합니다.", "모두가 타려면 우리는 승합차가 필요해요."], "ans": 2, "audio": "Test02_11.mp3"}, {"n": 12, "part": 2, "q": "Why has our director been out of the office all morning?", "qko": "우리 부장님은 왜 오전 내내 사무실에 없으셨나요?", "opts": ["Around seven o'clock.", "She's attending a workshop.", "Yes, your directions were useful."], "optko": ["7시쯤이요.", "그녀는 워크숍에 참석 중이에요.", "네, 당신의 안내는 유용했어요."], "ans": 1, "audio": "Test02_12.mp3"}, {"n": 13, "part": 2, "q": "Does the cleaning service send us monthly bills?", "qko": "청소 용역에서 우리에게 월간 청구서를 보내나요?", "opts": ["Yes, on the 1st.", "It's fine to pay with a credit card.", "I spent $50 last month."], "optko": ["네, 1일이요.", "신용 카드로 지불해도 괜찮아요.", "저는 지난달에 50달러를 썼어요."], "ans": 0, "audio": "Test02_13.mp3"}, {"n": 14, "part": 2, "q": "When do you want me to restock the shelves?", "qko": "당신은 제가 언제 선반을 다시 채우기를 원하시나요?", "opts": ["No, I think it is on the bottom shelf.", "Before taking your lunch break.", "In the storage room."], "optko": ["아니요, 맨 아래 선반에 있는 것 같아요.", "당신이 점심시간을 갖기 전에요.", "창고 안에요."], "ans": 1, "audio": "Test02_14.mp3"}, {"n": 15, "part": 2, "q": "How often do you go to Tokyo on business trips?", "qko": "당신은 얼마나 자주 도쿄로 출장을 가나요?", "opts": ["It's an event occurring in Tokyo.", "An agent will plan the trip.", "We no longer have a branch in that city."], "optko": ["그건 도쿄에서 일어나는 행사예요.", "대행자가 여행을 계획할 거예요.", "우리는 더 이상 그 도시에 지사가 없어요."], "ans": 2, "audio": "Test02_15.mp3"}, {"n": 16, "part": 2, "q": "Who should I submit my employment application to?", "qko": "제 구직 신청서를 누구에게 제출해야 하나요?", "opts": ["The woman behind the reception desk.", "You should include a résumé and cover letter.", "The position won't be vacant for another two weeks."], "optko": ["안내 데스크 뒤의 여자요.", "이력서와 자기소개서를 포함해야 해요.", "그 직무는 앞으로 2주 동안은 비어 있지 않을 거예요."], "ans": 0, "audio": "Test02_16.mp3"}, {"n": 17, "part": 2, "q": "Why don't we ask the baker to recommend a high quality bread flour?", "qko": "제빵사에게 고급 제빵용 밀가루를 추천해달라고 하는 게 어때요?", "opts": ["No, we've already arrived.", "I bought some cakes.", "Yes, that would be helpful."], "optko": ["아니요, 우리는 이미 도착했어요.", "전 케이크를 좀 샀어요.", "네, 그게 도움이 되겠네요."], "ans": 2, "audio": "Test02_17.mp3"}, {"n": 18, "part": 2, "q": "Would you organize the museum's charity luncheon?", "qko": "당신이 박물관의 자선행사를 위한 오찬을 준비해 주시겠어요?", "opts": ["We received a generous donation.", "It would be my pleasure.", "No, I don't need a ride."], "optko": ["우리는 후한 기부금을 받았어요.", "기꺼이 할게요.", "아니요, 태워주실 필요 없어요."], "ans": 1, "audio": "Test02_18.mp3"}, {"n": 19, "part": 2, "q": "You've reserved your seat for the concert already, haven't you?", "qko": "당신은 콘서트의 좌석을 이미 예약했죠, 안 그런가요?", "opts": ["I should be ready by 6 P.M.", "I'm going to do it now.", "No, it'll be my first time playing there."], "optko": ["전 오후 6시까지는 준비될 거예요.", "지금 할 거예요.", "아니요, 제가 그곳에서 연주하는 건 처음이 될 거예요."], "ans": 1, "audio": "Test02_19.mp3"}, {"n": 20, "part": 2, "q": "What is the company's reason for recalling the vehicle?", "qko": "회사에서 그 차량을 회수하는 이유가 무엇인가요?", "opts": ["No, I didn't receive a full refund.", "Consumers are reporting faulty brakes.", "They should be brought back to the store."], "optko": ["아니요, 저는 전액 환불을 받지 못했어요.", "소비자들이 결함이 있는 브레이크를 신고하고 있어요.", "그것들을 상점에 돌려줘야 해요."], "ans": 1, "audio": "Test02_20.mp3"}, {"n": 21, "part": 2, "q": "The conference on business strategies is going to be postponed.", "qko": "사업 전략에 관한 회의가 연기될 거예요.", "opts": ["Across from the convention center.", "That strategy was very effective.", "Oh, I didn't know that."], "optko": ["컨벤션 센터의 맞은편이요.", "그 전략은 매우 효과적이었어요.", "아, 전 몰랐어요."], "ans": 2, "audio": "Test02_21.mp3"}, {"n": 22, "part": 2, "q": "Where did you put our flight tickets to Vancouver?", "qko": "우리의 밴쿠버행 비행기 표를 어디에 두었나요?", "opts": ["I left them in my desk drawer.", "We need to hurry to catch the flight.", "I made a reservation this morning."], "optko": ["그것들을 제 책상 서랍 안에 두었어요.", "우린 그 비행기를 타기 위해 서둘러야 해요.", "오늘 아침에 예약했어요."], "ans": 0, "audio": "Test02_22.mp3"}, {"n": 23, "part": 2, "q": "Didn't the guests in Suite 234 request room service?", "qko": "스위트룸 234호의 고객들이 룸서비스를 요청하지 않았나요?", "opts": ["The kitchen staff will know.", "They have checked in.", "It's bigger than I had expected."], "optko": ["주방 직원이 알 거예요.", "그들은 체크인했어요.", "그건 제가 예상했던 것보다 더 크네요."], "ans": 0, "audio": "Test02_23.mp3"}, {"n": 24, "part": 2, "q": "Which shirts are currently on sale?", "qko": "어느 셔츠들이 현재 할인 중인가요?", "opts": ["Yes, 75 percent off.", "All of the ones on this rack.", "Let's go shopping at the Riverton Mall."], "optko": ["네, 75퍼센트 할인입니다.", "이 선반 위에 있는 것은 전부 다요.", "Riverton 몰로 쇼핑하러 갑시다."], "ans": 1, "audio": "Test02_24.mp3"}, {"n": 25, "part": 2, "q": "Why do you want to return this table?", "qko": "당신은 왜 이 탁자를 반품하길 원하시나요?", "opts": ["Thanks. I'll exchange it later.", "My turn is coming up next.", "It's too big for my living room."], "optko": ["감사합니다. 제가 나중에 그것을 교환할게요.", "제 차례가 다음으로 다가오고 있어요.", "그것은 제 거실에 너무 커요."], "ans": 2, "audio": "Test02_25.mp3"}, {"n": 26, "part": 2, "q": "I've decided which apartment I'm going to lease when I move to Madrid.", "qko": "저는 마드리드로 이사하면 어느 아파트를 임대할지 결정했어요.", "opts": ["I knew you were unhappy with your landlord.", "Great, that's one major decision.", "They're trying to sell their house."], "optko": ["당신이 임대주에게 불만스러워했다는 것을 알고 있었어요.", "잘됐네요, 그것은 하나의 중대한 결정이에요.", "그들은 집을 팔려고 노력하고 있어요."], "ans": 1, "audio": "Test02_26.mp3"}, {"n": 27, "part": 2, "q": "When will we leave for the company picnic?", "qko": "우리는 언제 회사 야유회를 위해 출발할 건가요?", "opts": ["At 10:45 this morning.", "I went to work yesterday.", "At the Central Park subway station."], "optko": ["오늘 오전 10시 45분에요.", "저는 어제 출근했어요.", "Central Park 지하철역에서요."], "ans": 0, "audio": "Test02_27.mp3"}, {"n": 28, "part": 2, "q": "Should we stay at the beach or head back to the hotel?", "qko": "우리는 해변에 머무를까요, 아니면 호텔로 돌아갈까요?", "opts": ["Some extra beach towels.", "OK, if you're done swimming.", "Let's relax here a bit longer."], "optko": ["여분의 해변용 수건 몇 장이요.", "좋아요, 당신이 수영을 다 하면요.", "여기서 좀 더 휴식을 취해요."], "ans": 2, "audio": "Test02_28.mp3"}, {"n": 29, "part": 2, "q": "Hasn't the technician fixed our network yet?", "qko": "기술자가 우리의 네트워크를 아직 수리하지 않았나요?", "opts": ["We met him at the networking event.", "No, he's still working on it.", "I'm glad we solved it together."], "optko": ["우린 그를 네트워킹 행사에서 만났어요.", "아니요, 그는 아직 그걸 작업하고 있어요.", "우리가 그것을 함께 해결해서 기뻐요."], "ans": 1, "audio": "Test02_29.mp3"}, {"n": 30, "part": 2, "q": "Do you know who the woman delivering the welcome address is?", "qko": "당신은 환영 연설을 하고 있는 저 여자가 누구인지 아나요?", "opts": ["Yes, it was delivered to my home last week.", "Her name is Kate Wong.", "I think it's on 17th Street."], "optko": ["네, 그것은 지난주에 우리 집으로 배달되었어요.", "그녀의 이름은 Kate Wong이에요.", "그것은 17번가에 있는 것 같아요."], "ans": 1, "audio": "Test02_30.mp3"}, {"n": 31, "part": 2, "q": "The Boston Herald reports that the Eastwood Public Library is closed for renovations.", "qko": "The Boston Herald지는 Eastwood 공립 도서관이 수리를 위해 문을 닫았다고 보도해요.", "opts": ["Have you completed the report?", "I have to renew my card next month.", "Really? When will it reopen?"], "optko": ["당신은 보고서를 완료했나요?", "다음 달에 제 카드를 갱신해야 해요.", "정말요? 언제 다시 문을 열까요?"], "ans": 2, "audio": "Test02_31.mp3"}], "sets34": [{"start": 32, "part": 3, "intro": "", "graphic": false, "speakers": "미국식 발음 → 캐나다식 발음", "audio": "Test02_32-34.mp3", "qs": [{"n": 32, "q": "Who is the woman?", "opts": ["A newspaper editor", "A television reporter", "A health-care worker", "A store owner"], "ans": 3, "ko": "여자는 누구인가?"}, {"n": 33, "q": "What information was incorrectly printed?", "opts": ["The location of a branch", "The date of an opening", "The name of a company", "The price of a product"], "ans": 1, "ko": "어떤 정보가 잘못 인쇄되었는가?"}, {"n": 34, "q": "What does the man offer to do?", "opts": ["Reprint an advertisement", "Proofread a newspaper article", "Inform a coworker of a mistake", "Transfer the woman's call"], "ans": 2, "ko": "남자는 무엇을 해주겠다고 제안하는가?"}], "script": [{"sp": "W", "en": "Hello. My name is Vanessa Johnson, and I'm calling because I want to report an error in your newspaper.", "ko": "안녕하세요. 제 이름은 Vanessa Johnson이고, 귀사의 신문에 있는 오류를 알리고 싶어 전화드립니다."}, {"sp": "M", "en": "What mistake did you discover, Ms. Johnson?", "ko": "무슨 오류를 발견하셨나요, Ms. Johnson?"}, {"sp": "W", "en": "Well . . . I'm the owner of the vitamin and supplement store called Lancaster Health and Nutrition. Yesterday, you published an article about our new branch that's going to open in Dalton Plaza next week. But the article said it's opening next month.", "ko": "음… 저는 Lancaster Health and Nutrition이라는 비타민 및 영양 보충제 가게의 주인이에요. 어제, 귀사에서 다음 주에 Dalton Plaza에 개장하는 저희의 새로운 지점에 관한 기사를 실었어요. 하지만 기사에는 그곳이 다음 달에 개장할 것이라고 쓰여 있었어요."}, {"sp": "M", "en": "Oh, I'm very sorry. I'll be certain to notify our news editor immediately. Once he verifies the misprint, I'm sure he'll arrange for a correction to be posted in tomorrow's edition.", "ko": "아, 정말 죄송합니다. 저희의 신문 편집자에게 반드시 바로 알리도록 하겠습니다. 그가 오자를 확인하자마자, 분명히 내일 신문에 게재되도록 수정 기사를 준비할 겁니다."}]}, {"start": 35, "part": 3, "intro": "", "graphic": false, "speakers": "영국식 발음 → 호주식 발음", "audio": "Test02_35-37.mp3", "qs": [{"n": 35, "q": "What type of event is taking place today?", "opts": ["A cooking course", "A food exposition", "A company gathering", "A restaurant opening"], "ans": 2, "ko": "오늘 어떤 종류의 행사가 일어나고 있는가?"}, {"n": 36, "q": "What was the man responsible for?", "opts": ["Listing new items on a menu", "Showing guests to their seats", "Preparing ingredients for a dish", "Tracking event attendance"], "ans": 3, "ko": "남자는 무엇에 책임이 있었는가?"}, {"n": 37, "q": "What will the man probably do next?", "opts": ["Bring dishes to a kitchen", "Serve some special meals", "Talk to a chef", "Change the time of an event"], "ans": 2, "ko": "남자는 다음에 무엇을 할 것 같은가?"}], "script": [{"sp": "W", "en": "It appears that we need more meals for tonight's year-end, corporate dinner party. Seven of our employees brought additional guests, but the cooks only prepared enough food for the confirmed number of guests.", "ko": "우리는 오늘 밤 회사 송년회 만찬 파티를 위한 음식이 더 필요한 것 같아요. 일곱 명의 우리 직원들이 추가 손님들을 데려왔는데, 요리사들은 확정된 수의 손님들에게 충분한 음식만 준비했어요."}, {"sp": "M", "en": "Hmm, that's odd. I was in charge of keeping track of the guest list, and just one person contacted me today to say that he was bringing an extra person with him.", "ko": "흠, 이상하네요. 제가 손님 명단을 기록하는 것을 맡았었는데, 딱 한 명만 오늘 제게 연락해서 추가 인원을 데려올 것이라 말했어요."}, {"sp": "W", "en": "Maybe some of them changed their minds at the last minute. Anyway, could you ask the chef to make a few more dishes?", "ko": "아마도 그들 중 몇몇이 마지막 순간에 마음을 바꾼 것 같아요. 어쨌든, 주방장에게 요리를 좀 더 만들어달라고 요청해 주시겠어요?"}, {"sp": "M", "en": "Sure. I'll head to the kitchen and find out if he can do that.", "ko": "물론이죠. 주방으로 가서 그가 그렇게 할 수 있는지 알아볼게요."}]}, {"start": 38, "part": 3, "intro": "", "graphic": false, "speakers": "캐나다식 발음 → 영국식 발음", "audio": "Test02_38-40.mp3", "qs": [{"n": 38, "q": "What is the conversation mainly about?", "opts": ["A company policy", "A training workshop", "A corporate fund-raiser", "An employee club"], "ans": 3, "ko": "대화는 주로 무엇에 관한 것인가?"}, {"n": 39, "q": "What does the woman mean when she says, \"I'm not very experienced\"?", "opts": ["She does not want to compete.", "She will inquire about an event.", "She cannot complete an assignment.", "She is eager to receive instruction."], "ans": 0, "ko": "여자는 \"저는 아주 능숙하지는 않거든요\"라고 말할 때 무엇을 의도하는가?"}, {"n": 40, "q": "What does the man say he will do this afternoon?", "opts": ["Pay an application fee", "Send a document", "Provide some equipment", "E-mail a group organizer"], "ans": 1, "ko": "남자는 오늘 오후에 무엇을 할 것이라고 말하는가?"}], "script": [{"sp": "M", "en": "Shannon, I noticed that you ride your bike to work. Did you know that some of the people in our department have formed a bicycle group?", "ko": "Shannon, 당신이 일하러 올 때 자전거를 타고 온다는 것을 알아챘어요. 우리 부서 사람들 중 일부가 자전거 동호회를 만든 것을 알고 있었나요?"}, {"sp": "W", "en": "Really? I hadn't heard that. Can you tell me more about it?", "ko": "정말요? 전 그것을 들은 적이 없어요. 그것에 대해 제게 더 말해주실 수 있나요?"}, {"sp": "M", "en": "Well, we meet every Saturday and go on long rides together. Some of us just enjoy the workout, while others are training for competitive events. Of course, participating in these races isn't a requirement for club members.", "ko": "음, 우리는 매주 토요일마다 만나서 함께 장거리 주행을 해요. 저희 중 일부는 단지 운동을 즐기는 한편, 다른 사람들은 경기를 위해 훈련을 하고 있어요. 물론, 이런 경기들에 참가하는 것이 동호회 회원들에게 필요조건은 아니에요."}, {"sp": "W", "en": "That's a relief. I'm not very experienced. But I do like the idea of getting some exercise. How do I join?", "ko": "안심이 되네요. 저는 아주 능숙하지는 않거든요. 하지만 운동을 한다는 계획은 좋아요. 어떻게 가입하면 되나요?"}, {"sp": "M", "en": "I'll e-mail you the registration form this afternoon.", "ko": "제가 당신에게 오늘 오후에 신청서를 이메일로 보내드릴게요."}]}, {"start": 41, "part": 3, "intro": "", "graphic": false, "speakers": "캐나다식 발음 → 미국식 발음", "audio": "Test02_41-43.mp3", "qs": [{"n": 41, "q": "What is the problem?", "opts": ["Insufficient funding was provided.", "A document was misplaced.", "A project was canceled.", "Incorrect information was submitted."], "ans": 3, "ko": "무엇이 문제인가?"}, {"n": 42, "q": "Where does the woman have to go?", "opts": ["To a product launch", "To a departmental meeting", "To a business lunch", "To an employee orientation"], "ans": 2, "ko": "여자는 어디에 가야 하는가?"}, {"n": 43, "q": "What does the man plan to do on Wednesday?", "opts": ["Organize an office space", "Contact some employees", "Release a company document", "Correct some charts"], "ans": 2, "ko": "남자는 수요일에 무엇을 할 계획인가?"}], "script": [{"sp": "M", "en": "After this morning's new recruit orientation, you said that you'd provide me with a list of the names of the new employees from each department. But the one you sent me was from the last orientation instead.", "ko": "오늘 아침 신입 사원 오리엔테이션 후에, 당신은 각 부서의 신입 사원들 명단을 제게 주겠다고 말했었어요. 하지만 당신이 제게 대신 보낸 것은 지난 오리엔테이션의 명단이었어요."}, {"sp": "W", "en": "Sorry about that. Is it OK if I get you the correct one later? I must go to an important lunch meeting with the funders of our new building project right now, so I don't have enough time at the moment.", "ko": "죄송해요. 올바른 명단을 나중에 드려도 될까요? 우리의 새로운 건설 프로젝트의 자금 제공자들과의 중요한 점심 회의에 지금 당장 가야 해서, 지금은 충분한 시간이 없어요."}, {"sp": "M", "en": "That's fine. Just remember to get it to me before you leave the office today. I'll need to enter their contact information into our database before I publish the new employee directory on Wednesday.", "ko": "괜찮아요. 오늘 당신이 퇴근하기 전에 그것을 제게 주어야 한다는 것만 기억해 주세요. 제가 수요일에 새로운 직원 전화번호부를 게재하기 전에 우리의 데이터베이스에 그들의 연락처를 기재해야 해요."}, {"sp": "W", "en": "I won't forget.", "ko": "잊지 않을게요."}]}, {"start": 44, "part": 3, "intro": "", "graphic": false, "speakers": "호주식 발음 → 영국식 발음", "audio": "Test02_44-46.mp3", "qs": [{"n": 44, "q": "What is the woman concerned about?", "opts": ["A product did poorly in a trial.", "Some complaints were made.", "An engineer intends to resign.", "Some measurements are inaccurate."], "ans": 1, "ko": "여자는 무엇을 걱정하는가?"}, {"n": 45, "q": "What did the man recently do?", "opts": ["Contacted a customer", "Carried out some tests", "Asked for a cost estimate", "Drafted a device manual"], "ans": 1, "ko": "남자는 최근에 무엇을 했는가?"}, {"n": 46, "q": "What does the man ask about?", "opts": ["An informational session", "An evaluation summary", "An assignment deadline", "A shift schedule"], "ans": 2, "ko": "남자는 무엇에 관해 문의하는가?"}], "script": [{"sp": "M", "en": "You want to see me, Ms. Collins?", "ko": "저를 만나고 싶으셨나요, Ms. Collins?"}, {"sp": "W", "en": "Yes. Many customers have provided negative feedback about the XLNC solar clocks. I'm a little worried. They say their machines aren't charging properly, which causes them to stop functioning after just a few days.", "ko": "네. 많은 고객들이 XLNC 태양열 시계에 관해 부정적인 의견을 주었어요. 저는 조금 걱정돼요. 그들은 기계가 제대로 충전이 되지 않는데, 이것이 단 며칠 후면 기계가 작동하는 것을 멈추게 한다고 해요."}, {"sp": "M", "en": "Bill Johnson from our engineering team and I recently tested 200 random units. They all worked perfectly. So, my guess is that consumers aren't using the devices properly. I think we need to clarify our user manual.", "ko": "우리 기술팀의 Bill Johnson과 제가 최근에 임의로 200개의 기기들을 검사했어요. 모두 완벽하게 작동했어요. 그래서, 제 추측은 고객들이 기기들을 제대로 사용하고 있지 않다는 것이에요. 우리의 사용자 설명서를 명확하게 해야 할 것 같아요."}, {"sp": "W", "en": "I see. We should also post information about it on our Web site. Can you please make a draft of that?", "ko": "그렇군요. 우리는 또한 웹사이트에도 이것에 관한 정보를 게시해야 해요. 당신이 그것의 초안을 만들어 주실 수 있나요?"}, {"sp": "M", "en": "OK. When do you want this done by?", "ko": "알겠어요. 이것이 언제까지 완성되길 원하시나요?"}, {"sp": "W", "en": "Early enough so that I can skim through it before my shift ends today.", "ko": "오늘 제 근무 교대 시간이 끝나기 전에 그것을 훑어볼 수 있도록 충분히 일찍이요."}]}, {"start": 47, "part": 3, "intro": "", "graphic": false, "speakers": "호주식 발음 → 미국식 발음", "audio": "Test02_47-49.mp3", "qs": [{"n": 47, "q": "Where most likely is the conversation taking place?", "opts": ["At a post office", "At an event hall", "At a print shop", "At a photo studio"], "ans": 2, "ko": "대화는 어디에서 일어나고 있는 것 같은가?"}, {"n": 48, "q": "What does the man ask the woman to do?", "opts": ["Mail an invitation", "Suggest a product", "Verify a payment method", "Contact a delivery service"], "ans": 1, "ko": "남자는 여자에게 무엇을 해달라고 요청하는가?"}, {"n": 49, "q": "What information does the woman provide the man with?", "opts": ["What size of sheet is needed", "Why a shipment has not arrived", "When a celebration will be held", "How much an order will cost"], "ans": 3, "ko": "여자는 남자에게 어떤 정보를 제공하는가?"}], "script": [{"sp": "M", "en": "Excuse me. I require some assistance. I'd like you to print 100 wedding invitations for me, but I'm not sure which type of paper to use. I want the invitations to look nice but also be durable. Do you have any recommendations?", "ko": "실례합니다. 도움이 좀 필요해요. 청첩장 100장을 인쇄해주셨으면 하는데, 어떤 종류의 종이를 사용할지 모르겠어요. 저는 초대장들이 멋져 보일 뿐만 아니라 견고했으면 해요. 추천해주실 것이 있나요?"}, {"sp": "W", "en": "I suggest trying our store's glossy card stock. This high-quality paper is very strong, so it doesn't tear easily. It'd be ideal if you intend to deliver the invitations through the mail.", "ko": "저희 가게의 광택이 있는 인쇄용지를 사용해보시는 것을 추천해요. 이 고품질 종이는 매우 튼튼해서, 쉽게 찢어지지 않아요. 만약 우편으로 초대장들을 보내려고 생각하신다면 이것이 이상적일 거예요."}, {"sp": "M", "en": "That sounds perfect. How much will the order cost?", "ko": "완벽한 것 같네요. 주문 비용은 얼마나 들까요?"}, {"sp": "W", "en": "Well, each sheet of card stock costs 50¢ to print, and you can fit two invitations per sheet . . . So, your grand total will be $25.", "ko": "음, 인쇄용지의 각 장을 인쇄하는 데 50센트의 비용이 들고, 한 장당 두 개의 초대장을 맞출 수 있어요… 그래서, 고객님의 총액은 25달러일 거예요."}]}, {"start": 50, "part": 3, "intro": "", "graphic": false, "speakers": "캐나다식 발음 → 미국식 발음", "audio": "Test02_50-52.mp3", "qs": [{"n": 50, "q": "Why does the man visit the business?", "opts": ["To request a discount", "To confirm a payment", "To speak with an instructor", "To inquire about an offering"], "ans": 3, "ko": "남자는 왜 업체를 방문하는가?"}, {"n": 51, "q": "Why was the evening class canceled?", "opts": ["A trainer was unavailable.", "A room had been booked.", "Student registration was low.", "A facility's hours were reduced."], "ans": 2, "ko": "저녁 수업은 왜 취소되었는가?"}, {"n": 52, "q": "What does the woman offer to do?", "opts": ["Review a business pamphlet", "Deal with a transaction", "Suggest an alternative course", "Get a handout"], "ans": 3, "ko": "여자는 무엇을 해주겠다고 제안하는가?"}], "script": [{"sp": "M", "en": "Hello. I read about the fitness courses your business offers in a flyer. I'm interested in the weight-training class. When is it held?", "ko": "안녕하세요. 전단지에서 당신의 업체가 제공하는 체력 단련 강좌들에 관해 읽었어요. 저는 웨이트 트레이닝 수업에 관심이 있어요. 그것이 언제 열리나요?"}, {"sp": "W", "en": "That one is held once a week on Saturday, from 9 A.M. to 1 P.M. in our largest room. We used to offer a second session at 7 P.M., but not many people signed up, so we decided to cancel it.", "ko": "그 강좌는 일주일에 한 번 토요일에, 오전 9시부터 오후 1시까지 저희의 가장 큰 방에서 열립니다. 저희는 오후 7시에 두 번째 수업을 제공했었지만, 많은 사람들이 등록하지 않아서 그 수업을 취소하기로 결정했습니다."}, {"sp": "M", "en": "Oh, that's OK. I wasn't planning on coming in then, anyway. The earlier option should work for me. So, I'd like to know a bit more about the details of the session.", "ko": "아, 괜찮아요. 어차피 저는 그때 올 계획은 아니었어요. 더 이른 시간의 선택권이 제게 맞을 거예요. 그래서, 그 수업의 세부 사항에 대해 좀 더 알고 싶어요."}, {"sp": "W", "en": "Would you like me to grab you an informational pamphlet? It'll explain everything you need to know.", "ko": "제가 정보 소책자를 하나 드릴까요? 그것이 당신이 알고 싶어 하는 모든 것을 설명해줄 거예요."}]}, {"start": 53, "part": 3, "intro": "", "graphic": false, "speakers": "호주식 발음 → 영국식 발음 → 미국식 발음", "audio": "Test02_53-55.mp3", "qs": [{"n": 53, "q": "Who most likely is the man?", "opts": ["An equipment salesperson", "A repair technician", "A building inspector", "A construction worker"], "ans": 1, "ko": "남자는 누구인 것 같은가?"}, {"n": 54, "q": "What problem does the man mention?", "opts": ["Some instructions have been misplaced.", "Some parts have not been delivered.", "A component is malfunctioning.", "A machine was never installed."], "ans": 2, "ko": "남자는 어떤 문제를 언급하는가?"}, {"n": 55, "q": "Why will Janice call the building manager?", "opts": ["To request a replacement part", "To report on some work", "To obtain access to an office", "To arrange an appointment"], "ans": 1, "ko": "Janice는 왜 건물 관리자에게 전화할 것인가?"}], "script": [{"sp": "M", "en": "Excuse me. I've come to your office because I received a service request from Sarah Long.", "ko": "실례합니다. Sarah Long으로부터 서비스 요청을 받아서 당신의 사무실에 왔습니다."}, {"sp": "W1", "en": "Yes. Um . . . her desk is next to mine. Sarah, the repairperson from Raymond is here to fix the water cooler.", "ko": "네. 음… 그녀의 책상은 제 책상 옆이에요. Sarah, Raymond사의 수리공이 냉수기를 고치기 위해 왔어요."}, {"sp": "W2", "en": "Oh, sorry. I was just finishing up a conference call. Anyway, the cooler is right here behind my desk.", "ko": "아, 죄송해요. 저는 막 전화 회의를 끝내는 중이었어요. 어쨌든, 냉수기는 바로 여기 제 책상 뒤에 있어요."}, {"sp": "M", "en": "Water is leaking from the device's spout, right?", "ko": "물이 기기의 관에서 새고 있죠, 맞나요?"}, {"sp": "W2", "en": "Yeah. I noticed it dripping this morning.", "ko": "네. 물이 떨어지고 있는 것을 오늘 아침에 알아챘어요."}, {"sp": "M", "en": "Hmm . . . the spout isn't working correctly and needs to be replaced.", "ko": "흠… 관이 제대로 작동하고 있지 않아서 교체되어야 해요."}, {"sp": "W2", "en": "OK. However, before you begin, I've got to notify the building manager that a repair is going to be made. Janice, what is Mr. Renner's extension?", "ko": "그렇군요. 하지만 당신이 시작하기 전에, 저는 건물 관리자에게 수리가 진행될 거라고 알려야 해요. Janice, Mr. Renner의 내선 번호가 뭔가요?"}, {"sp": "W1", "en": "It's 6849. I'll call him and tell him for you.", "ko": "6849예요. 제가 당신을 위해 그에게 전화해서 말할게요."}, {"sp": "W2", "en": "Great. I appreciate it.", "ko": "좋아요. 감사해요."}]}, {"start": 56, "part": 3, "intro": "", "graphic": false, "speakers": "영국식 발음 → 캐나다식 발음", "audio": "Test02_56-58.mp3", "qs": [{"n": 56, "q": "Where most likely are the speakers?", "opts": ["At a train station", "At a bus stop", "At a taxi stand", "At an airport"], "ans": 3, "ko": "화자들은 어디에 있는 것 같은가?"}, {"n": 57, "q": "Why is the woman unable to board?", "opts": ["She left a meeting late.", "She could not find a taxi.", "She has forgotten her ticket.", "She was caught in traffic."], "ans": 3, "ko": "여자는 왜 탑승할 수 없는가?"}, {"n": 58, "q": "What does the man offer to do?", "opts": ["Direct the woman to a gate", "Provide a seat upgrade", "Make another booking", "Store some extra luggage"], "ans": 2, "ko": "남자는 무엇을 해주겠다고 제안하는가?"}], "script": [{"sp": "W", "en": "Hello. My name is Annabel Christiansen. I'm here to check in for the 5:40 P.M. flight to London. I have my passport and ticket here.", "ko": "안녕하세요. 제 이름은 Annabel Christiansen입니다. 오후 5시 40분 런던행 항공편을 위한 탑승 수속을 밟으러 왔습니다. 여기 제 여권과 티켓이 있어요."}, {"sp": "M", "en": "I'm sorry. You've arrived too late, Ms. Christiansen. Check-in for that flight closed 20 minutes ago. There won't be enough time for you to reach the gate before takeoff.", "ko": "죄송합니다. 너무 늦게 도착하셨습니다, Ms. Christiansen. 그 항공편의 탑승 수속은 20분 전에 마감되었습니다. 고객님께서 이륙 전에 탑승구까지 도착할 충분한 시간이 없을 거예요."}, {"sp": "W", "en": "Oh, no. I was worried this was going to happen, seeing as my taxi was stuck in traffic on the way here. Are there any other flights today that I can take instead?", "ko": "아, 이런. 제 택시가 여기로 오는 길에 교통이 정체되었던 것 때문에, 이런 일이 일어날 것이라고 걱정했었어요. 오늘 제가 대신 탈 수 있는 다른 항공편들이 있나요?"}, {"sp": "M", "en": "Yes, we still have seats available on the one that leaves at 10:30 P.M. For a $100 fee, I can update your reservation and issue you another ticket.", "ko": "네, 오후 10시 30분에 떠나는 항공편에 아직 이용 가능한 좌석들이 있습니다. 100달러의 요금으로, 고객님의 예약 내역을 업데이트하고 다른 티켓을 발행해드릴 수 있습니다."}]}, {"start": 59, "part": 3, "intro": "", "graphic": false, "speakers": "캐나다식 발음 → 영국식 발음", "audio": "Test02_59-61.mp3", "qs": [{"n": 59, "q": "Who most likely is the woman?", "opts": ["A keynote speaker", "An event organizer", "A corporate spokesperson", "A financial advisor"], "ans": 3, "ko": "여자는 누구인 것 같은가?"}, {"n": 60, "q": "What will the woman do in April?", "opts": ["Give a speech", "Travel to another country", "Conduct training", "Attend a seminar"], "ans": 1, "ko": "여자는 4월에 무엇을 할 것인가?"}, {"n": 61, "q": "Why does the man say, \"It'll be held on April 4\"?", "opts": ["To imply that another speaker is available", "To suggest that the woman postpone a visit", "To indicate that the woman will miss an event", "To announce a planned schedule change"], "ans": 2, "ko": "남자는 왜 \"행사는 4월 4일에 열릴 거예요\"라고 말하는가?"}], "script": [{"sp": "M", "en": "Hello, Ms. Law. My name is Lance Graner, and I am organizing a conference in April for young professionals who are just entering the field of finance. As you are an investment consultant for a respected firm, I am calling to offer you a paid speaking opportunity at the conference.", "ko": "안녕하세요, Ms. Law. 제 이름은 Lance Graner이고, 재정 분야에 갓 들어온 젊은 전문가들을 위해 4월에 콘퍼런스를 기획하고 있어요. 당신은 높이 평가되는 회사의 투자 고문이시기 때문에, 당신에게 콘퍼런스에서의 유급 연설 기회를 제안하기 위해 전화드립니다."}, {"sp": "W", "en": "Well, I'll be unavailable in early April as I'm planning to visit one of our offices abroad during that time. However, as long as the event takes place after April 15, I can participate.", "ko": "글쎄요, 저는 4월 초에 해외에 있는 저희 사무실들 중 한 곳을 방문하려고 계획 중이기 때문에 그 시기 동안에는 시간이 안 될 거예요. 하지만, 그 행사가 4월 15일 이후에 개최된다면, 참석할 수 있어요."}, {"sp": "M", "en": "Hmm . . . It'll be held on April 4. But I'll contact you if we have other speaking opportunities in the future.", "ko": "흠… 행사는 4월 4일에 열릴 거예요. 하지만 만약 추후에 다른 연설 기회가 있다면 당신에게 연락드릴게요."}]}, {"start": 62, "part": 3, "intro": "", "graphic": true, "speakers": "영국식 발음 → 캐나다식 발음", "audio": "Test02_62-64.mp3", "qs": [{"n": 62, "q": "What is the woman's problem?", "opts": ["She cannot attend a meeting.", "She was not able to finish a project.", "She does not understand a request.", "She is not pleased with a service."], "ans": 0, "ko": "여자의 문제점은 무엇인가?"}, {"n": 63, "q": "Look at the graphic. What information will appear at the bottom of the billboard?", "opts": ["The company name", "The address", "The event date", "The slogan"], "ans": 1, "ko": "시각 자료를 보시오. 무슨 정보가 광고판의 맨 아래에 나타날 것인가?"}, {"n": 64, "q": "What does the man offer to do?", "opts": ["Modify a color scheme", "Seek feedback from a manager", "Send another draft", "Inform a client about a change"], "ans": 2, "ko": "남자는 무엇을 해주겠다고 제안하는가?"}], "script": [{"sp": "W", "en": "Mathew, it's Claudia. Something unexpected came up, so I won't be able to meet to talk about the billboard design today.", "ko": "Mathew, 저 Claudia예요. 예상치 못한 일이 생겨서, 오늘 광고판 디자인에 대해 이야기하기 위해 만날 수 없을 거예요."}, {"sp": "M", "en": "If you have a minute, we could just discuss it now.", "ko": "잠깐 시간이 되신다면, 우리는 그것에 대해 지금 논의할 수 있을 것 같아요."}, {"sp": "W", "en": "Sure.", "ko": "물론이죠."}, {"sp": "M", "en": "OK. So, how do you like the first draft that I sent you?", "ko": "좋아요. 그러면, 제가 보내드린 첫 번째 도안은 어떠세요?"}, {"sp": "W", "en": "The font is great. My only concern is how the information is arranged. Personally, I think we should switch the positions of the address and the slogan. It would be better if the slogan appeared directly under the company name. The date is fine where it is, though.", "ko": "서체는 훌륭해요. 저의 유일한 걱정은 정보가 어떻게 배열되는지예요. 개인적으로, 저는 우리가 주소와 슬로건의 위치를 바꿔야 한다고 생각해요. 슬로건이 회사 이름 바로 아래에 나타나면 더 좋을 거예요. 날짜는 지금 있는 위치가 괜찮지만요."}, {"sp": "M", "en": "That's a simple change. I can make it and e-mail you the revised version sometime this afternoon.", "ko": "간단한 수정이네요. 제가 변경해서 수정된 버전을 오늘 오후 중에 이메일로 보내드릴 수 있어요."}], "gimg": "hk2_t2_g62.jpg"}, {"start": 65, "part": 3, "intro": "", "graphic": true, "speakers": "호주식 발음 → 영국식 발음", "audio": "Test02_65-67.mp3", "qs": [{"n": 65, "q": "Who most likely are the speakers?", "opts": ["Television program hosts", "Event planners", "Food critics", "Dining establishment personnel"], "ans": 3, "ko": "화자들은 누구인 것 같은가?"}, {"n": 66, "q": "According to the woman, what happened last weekend?", "opts": ["A popular local show was delayed.", "A business was at full capacity.", "A supervisor made an announcement.", "A worker held a surprise celebration."], "ans": 1, "ko": "여자에 따르면, 지난 주말에 무슨 일이 일어났는가?"}, {"n": 67, "q": "Look at the graphic. Which channel will Harold Newman appear on?", "opts": ["Channel 3", "Channel 5", "Channel 7", "Channel 10"], "ans": 1, "ko": "시각 자료를 보시오. Harold Newman은 어느 채널에 출연할 것인가?"}], "script": [{"sp": "M", "en": "The restaurant's opening week was rather successful, wouldn't you say?", "ko": "식당의 개업 첫 주가 꽤 성공적이었어요, 그렇지 않나요?"}, {"sp": "W", "en": "Absolutely. We exceeded our expected guest numbers, and the restaurant was fully booked last weekend.", "ko": "물론이에요. 우리는 예상 손님 수를 넘었고, 지난 주말에는 식당의 예약이 꽉 찼어요."}, {"sp": "M", "en": "Yeah. And many of the people who came said they were going to post about our restaurant on their social networking pages. That's great publicity.", "ko": "네, 그리고 방문했던 많은 사람들이 우리 식당에 관해 그들의 소셜 네트워킹 페이지에 글을 올릴 것이라고 말했어요. 그것은 대단한 홍보예요."}, {"sp": "W", "en": "Also, our publicist, Harold Newman, will be appearing on Morning Buzz tomorrow. That will be sure to help us gain even more positive public attention.", "ko": "또한, 우리의 홍보 담당자인 Harold Newman이 내일 Morning Buzz에 출연할 거예요. 그것은 분명 우리가 한층 더 긍정적인 대중의 관심을 얻을 수 있도록 도와줄 거예요."}, {"sp": "M", "en": "That's great. A lot of people in the area watch that program. We should get a lot of new customers.", "ko": "정말 잘됐네요. 이 지역의 많은 사람들이 그 프로그램을 시청해요. 우리는 많은 새로운 고객들을 얻을 거예요."}], "gimg": "hk2_t2_g65.jpg"}, {"start": 68, "part": 3, "intro": "", "graphic": true, "speakers": "호주식 발음 → 미국식 발음", "audio": "Test02_68-70.mp3", "qs": [{"n": 68, "q": "What will take place this evening?", "opts": ["A product launch", "A charity dinner", "A wedding celebration", "An anniversary ceremony"], "ans": 3, "ko": "오늘 저녁에 무엇이 열릴 것인가?"}, {"n": 69, "q": "What did the man already do?", "opts": ["Cleared away some tables", "Threw out spoiled ingredients", "Welcomed some guests", "Decorated a space"], "ans": 3, "ko": "남자는 이미 무엇을 했는가?"}, {"n": 70, "q": "Look at the graphic. Which amount will be changed?", "opts": ["2.5 pounds", "3 pounds", "1.5 pounds", "4 pounds"], "ans": 2, "ko": "시각 자료를 보시오. 어떤 양이 변경될 것인가?"}], "script": [{"sp": "M", "en": "Preparations for this evening are coming along well. Tables and chairs have been set up for the 75 guests coming to celebrate their company's founding. Plus, I've placed flowers on the tables and put up some other decorations. How is everything in the kitchen going?", "ko": "오늘 저녁을 위한 준비가 잘 되어 가고 있어요. 그들의 회사 창립을 기념하기 위해 오시는 75명의 내빈을 위한 식탁과 의자들이 마련되었어요. 또한, 저는 식탁에 꽃을 올려두었고 다른 장식들을 두었어요. 주방에서는 모든 것이 어떻게 되어가고 있나요?"}, {"sp": "W", "en": "There was a mix-up with our food supplier. Only half of the vegetables we requested were dropped off this morning.", "ko": "우리의 식품 공급업체와 혼선이 있었어요. 우리가 요청한 채소 중 오직 절반만 오늘 아침에 배달되었어요."}, {"sp": "M", "en": "Oh, no. Do you want me to go buy the ingredients we need?", "ko": "아, 이런. 제가 가서 우리가 필요한 재료들을 사 올까요?"}, {"sp": "W", "en": "OK. Here's a list of everything I require. Oh, hold on . . . I need to make one change. You should get two pounds of carrots. The amounts for the onions and the others are correct though.", "ko": "좋아요. 여기 제가 필요한 모든 것의 목록이에요. 아, 잠시만요… 하나를 변경해야 해요. 당신은 당근 2파운드를 사야 해요. 그래도 양파와 다른 것들의 양은 정확해요."}], "gimg": "hk2_t2_g68.jpg"}, {"start": 71, "part": 4, "intro": "", "graphic": false, "speakers": "영국식 발음", "audio": "Test02_71-73.mp3", "qs": [{"n": 71, "q": "What is the purpose of the message?", "opts": ["To explain a premium increase", "To provide insurance information", "To apologize for a miscalculation", "To describe a loyalty program"], "ans": 1, "ko": "메시지의 목적은 무엇인가?"}, {"n": 72, "q": "What detail does the speaker need?", "opts": ["A coverage start date", "A driving test score", "A transaction amount", "A vehicle type"], "ans": 3, "ko": "화자는 어떤 세부 사항을 필요로 하는가?"}, {"n": 73, "q": "What does the speaker ask the listener to do?", "opts": ["Review a quote online", "Arrange an appointment", "Return a phone call", "Renew a contract"], "ans": 2, "ko": "화자는 청자에게 무엇을 해달라고 요청하는가?"}], "script": [{"sp": "W", "en": "Good afternoon, Mr. Jackson. This is Claudia Omar, from Proactive Insurance, responding to the voice mail you left me yesterday. You mentioned you'd like to learn more about motorcycle insurance. Well, our most popular plan is the Platinum Protection package, which provides you up to $250,000 in coverage, and I think it would be your best choice. The premium for the plan varies considerably depending on the motorbike you have, so I'll need to know the brand and model of your bike before I can give you an accurate quote. Please call me back today with those details if you can. Thanks.", "ko": "안녕하세요, Mr. Jackson. 고객님께서 어제 저에게 남기신 음성 메시지에 답변을 드리는 Proactive 보험사의 Claudia Omar입니다. 고객님께서는 오토바이 보험에 대해 더 알고 싶다고 하셨습니다. 음, 저희의 가장 인기 있는 상품은 보상 범위 내에서 25만 달러까지 지급해 드리는 Platinum Protection 패키지이며, 이것이 고객님께 최선의 선택일 것 같습니다. 이 상품의 보험료는 고객님께서 소유하신 오토바이에 따라 상당히 달라지므로, 제가 정확한 견적가를 전달드리기 전에 저는 고객님의 오토바이 브랜드와 모델을 알아야 할 것입니다. 가능하시다면 그러한 세부 사항들과 함께 오늘 제게 다시 전화해 주시기 바랍니다. 감사합니다."}]}, {"start": 74, "part": 4, "intro": "", "graphic": false, "speakers": "미국식 발음", "audio": "Test02_74-76.mp3", "qs": [{"n": 74, "q": "Where most likely is the talk taking place?", "opts": ["At a medical convention", "At a press conference", "At a shareholder's meeting", "At a fund-raising event"], "ans": 1, "ko": "담화는 어디에서 일어나고 있는 것 같은가?"}, {"n": 75, "q": "According to the speaker, what will happen in nine months?", "opts": ["A charity goal will be achieved.", "A facility will be completed.", "A new medication will be released.", "An operations manager will be promoted."], "ans": 1, "ko": "화자에 따르면, 9개월 후에 무슨 일이 일어날 것인가?"}, {"n": 76, "q": "What will be made available in the future?", "opts": ["A preview of an upcoming product line", "Details about a recently constructed facility", "An overview of the company's research projects", "Information about employment opportunities"], "ans": 3, "ko": "미래에 무엇이 이용 가능해질 것인가?"}], "script": [{"sp": "M", "en": "I appreciate you joining us at Fradston Pharmaceuticals' media event. I'm delighted to be here today, as Fradston's newly appointed chief executive officer, to announce our intention to build a new research center in downtown Atlanta. This center will serve as the hub for all of our medical research and is scheduled to open in nine months. The facility is expected to contribute to the creation of over 200 new jobs. More details about these will be posted on our Web site at a later date. We at Fradston hope that this development will solidify the company's position as the nation's top provider of pharmaceutical products.", "ko": "Fradston 제약회사의 언론 행사에 참여해 주셔서 감사합니다. Fradston사의 새롭게 임명된 최고 운영 책임자로서, 애틀랜타 시내에 새로운 연구 센터를 건설하고자 하는 저희의 계획을 발표하기 위해 오늘 이 자리에 있게 되어 기쁩니다. 이 센터는 저희의 모든 의학 연구의 중추 역할을 할 것이며 9개월 후에 열 예정입니다. 이 시설은 200개 이상의 새로운 일자리 창출에 기여할 것으로 예상됩니다. 이 일자리들에 관한 더 자세한 내용은 추후 저희 웹사이트에 게시될 것입니다. 저희 Fradston사에서는 이번 확장이 국내 최고 제약품 공급업체로서 회사의 위치를 확고히 하길 희망합니다."}]}, {"start": 77, "part": 4, "intro": "", "graphic": false, "speakers": "캐나다식 발음", "audio": "Test02_77-79.mp3", "qs": [{"n": 77, "q": "According to the speaker, what do some workers plan to do?", "opts": ["Take part in a festival", "Undergo some special training", "Enter a cooking competition", "Modify a restaurant menu"], "ans": 0, "ko": "화자에 따르면, 일부 직원들은 무엇을 할 계획인가?"}, {"n": 78, "q": "When will the store return to its regular hours?", "opts": ["On June 8", "On June 9", "On June 10", "On June 11"], "ans": 2, "ko": "매장은 언제 정상 영업시간으로 돌아갈 것인가?"}, {"n": 79, "q": "How can listeners request a reservation?", "opts": ["By texting a restaurant", "By leaving a voice message", "By visiting a company Web site", "By sending an e-mail"], "ans": 1, "ko": "청자들은 어떻게 예약을 요청할 수 있는가?"}], "script": [{"sp": "M", "en": "You have reached Cedar Kitchen, Houston's number-one spot for contemporary dining. As our staff is participating in the Southwestern Food Festival June 8 and June 9, we will be closing at 1 P.M. each day. Our normal hours of operation of 11 A.M. to 10 P.M. will resume on Wednesday, June 10. We greatly appreciate your patience in this matter. For details about menu offerings, please press \"one\". For reservations, press \"two\" and record your contact information and desired reservation time after the tone. Specific details regarding the Southwestern Food Festival may be obtained by visiting our Web site.", "ko": "현대적인 식사를 위한 휴스턴 제일의 장소인 Cedar Kitchen입니다. 저희 직원들이 6월 8일과 6월 9일에 남서부 음식 축제에 참가할 것이기 때문에, 해당 날짜에는 오후 1시에 문을 닫을 것입니다. 오전 11시부터 오후 10시까지의 저희의 정상 영업시간은 6월 10일 수요일에 재개될 것입니다. 이 문제에 대한 고객님의 인내에 대단히 감사드립니다. 메뉴 제공에 관한 세부 사항을 위해서는, \"1번\"을 눌러 주세요. 예약을 위해서는, \"2번\"을 누르시고 삐 소리 후 고객님의 연락처와 희망하시는 예약 시간을 녹음해 주세요. 남서부 음식 축제에 관한 구체적인 세부 사항은 저희 웹사이트에 방문함으로써 얻으실 수 있습니다."}]}, {"start": 80, "part": 4, "intro": "", "graphic": false, "speakers": "호주식 발음", "audio": "Test02_80-82.mp3", "qs": [{"n": 80, "q": "What is the announcement mainly about?", "opts": ["A mobile application", "An employee database", "A client registry", "An online class"], "ans": 0, "ko": "공지는 주로 무엇에 관한 것인가?"}, {"n": 81, "q": "What did the speaker do yesterday?", "opts": ["Set up a company's network", "Met with some team leaders", "Distributed documents to workers", "Tested out a program"], "ans": 3, "ko": "화자는 어제 무엇을 했는가?"}, {"n": 82, "q": "What does the speaker mean when he says, \"you won't need to set aside much time for this\"?", "opts": ["A meeting topic will be familiar.", "A tutorial has been shortened.", "A process can be learned quickly.", "A form is very simple to fill out."], "ans": 2, "ko": "화자는 \"여러분이 이것을 위해 많은 시간을 비워두실 필요는 없을 겁니다\"라고 말할 때 무엇을 의도하는가?"}], "script": [{"sp": "M", "en": "Our company has developed a new application for employees to access our Intranet system from their smart phones. I reviewed some sales and personnel records with it yesterday, and I think everyone will be happy with this change. It will allow our team members to view client records while visiting customers outside of the office. The application's creator, Jay Kim, has volunteered to give everyone a tutorial this afternoon. Navigating it is pretty straightforward, so you won't need to set aside much time for this. Mr. Kim will be waiting for you all in Room 230 at 3 o'clock.", "ko": "우리 회사는 직원들이 스마트폰으로 우리 인트라넷에 접근하도록 하기 위해 새로운 애플리케이션을 개발했습니다. 제가 어제 그것으로 몇몇 영업 및 인사 기록들을 살펴보았고, 모든 사람들이 이 변화에 만족할 것으로 생각합니다. 그것은 우리 팀원들이 사무실 밖에서 고객들을 방문하는 동안 고객 기록을 볼 수 있도록 해줄 것입니다. 애플리케이션의 개발자인 Jay Kim이 오늘 오후에 모두에게 개별 지도 시간을 제공하기로 자원했습니다. 그것을 다루는 것은 꽤 간단해서, 여러분이 이것을 위해 많은 시간을 비워두실 필요는 없을 겁니다. Mr. Kim이 여러분 모두를 3시에 230호에서 기다리고 있을 것입니다."}]}, {"start": 83, "part": 4, "intro": "", "graphic": false, "speakers": "미국식 발음", "audio": "Test02_83-85.mp3", "qs": [{"n": 83, "q": "What is the purpose of the talk?", "opts": ["To explain an enrollment procedure", "To provide details about a program", "To encourage listeners to volunteer", "To introduce a guest speaker"], "ans": 1, "ko": "담화의 목적은 무엇인가?"}, {"n": 84, "q": "What does the speaker say about some project managers?", "opts": ["They will lead presentations.", "They will be selecting teams.", "They will conduct evaluations.", "They will be assessing proposals."], "ans": 0, "ko": "화자는 프로젝트 관리자들에 관해 무엇을 말하는가?"}, {"n": 85, "q": "What will be provided to the listeners?", "opts": ["A free meal", "Copies of a survey form", "Contact details for speakers", "An information packet"], "ans": 3, "ko": "청자들에게 무엇이 제공될 것인가?"}], "script": [{"sp": "M", "en": "Hello, and welcome to our annual two-day seminar on project management. This year's event promises to be very special as we have a wide range of speakers. Now, I'd like to give you some information about our schedule. We are going to focus on planning and implementing projects for the first day and on evaluating results for the second. Both days will follow the same basic pattern. The mornings are going to begin with presentations by experienced project managers and end with panel discussions and question-and-answer sessions. In the afternoons, we'll break into small groups to develop action plans for specific projects. OK . . . my assistant will now hand out information packets that contain details about what will be covered during the seminar.", "ko": "안녕하세요, 프로젝트 관리에 관한 이틀간의 연례 세미나에 오신 것을 환영합니다. 올해의 행사는 우리에게 다양한 발표자들이 있어 매우 특별할 듯합니다. 이제, 여러분께 우리의 일정에 관한 정보를 드리고 싶습니다. 첫째 날에는 프로젝트 계획과 실행에, 그리고 둘째 날에는 성과 평가에 초점을 맞출 것입니다. 이틀 모두 같은 기본 패턴을 따르게 될 것입니다. 오전 시간은 경험이 풍부한 프로젝트 관리자들에 의한 발표로 시작해 공개 토론 및 질의응답 시간으로 끝나게 될 것입니다. 오후에는, 구체적인 프로젝트를 위한 실행 방안을 개발하기 위해 소그룹으로 나뉠 것입니다. 좋습니다… 이제 제 조수가 세미나 동안 다뤄질 것에 대한 세부 사항을 포함하고 있는 자료 묶음을 나눠드릴 것입니다."}]}, {"start": 86, "part": 4, "intro": "", "graphic": false, "speakers": "호주식 발음", "audio": "Test02_86-88.mp3", "qs": [{"n": 86, "q": "What will most likely happen at the end of May?", "opts": ["A firm will open a new office.", "A business deal will be completed.", "An executive will leave a job.", "An industry event will be held."], "ans": 2, "ko": "5월 말에 무슨 일이 일어날 것 같은가?"}, {"n": 87, "q": "What does the speaker imply when he says, \"it currently employs about 15,000 staff members\"?", "opts": ["A corporate headquarters must be expanded.", "A business has experienced tremendous growth.", "An organization needs to reduce its workforce.", "A company merger will impact many people."], "ans": 1, "ko": "화자는 \"현재 15,000여 명의 직원들을 고용하고 있습니다\"라고 말할 때 무엇을 의도하는가?"}, {"n": 88, "q": "What is mentioned about Dale Fenny?", "opts": ["He founded the firm.", "He made a public announcement.", "He has applied for a new job.", "He is in the financial field."], "ans": 3, "ko": "Dale Fenny에 관해 무엇이 언급되는가?"}], "script": [{"sp": "M", "en": "In business news, the multinational technology company Core Resources has announced that its CEO, Kerry Rose, will be stepping down from her position at the end of May. Under Ms. Rose's leadership, the company grew to be the world's third-largest software developer. It had under 8,000 workers when she started, while it currently employs about 15,000 staff members. Although Core Resources has yet to release her replacement's name to the public—and most likely won't do so until closer to Ms. Rose's departure—some analysts are speculating about who the next leader of the company might be. One widely discussed candidate is Dale Fenny, the company's current chief financial officer.", "ko": "비즈니스 뉴스로, 다국적 기술 회사 Core Resources사는 최고 경영자인 Kerry Rose가 5월 말에 그녀의 직위에서 물러날 것이라고 발표했습니다. Ms. Rose의 지도 하에, 회사는 전 세계에서 세 번째로 큰 소프트웨어 개발업체로 성장했습니다. 그녀가 시작했을 때는 그것은 8,000명 이하의 직원을 가졌지만, 현재 15,000여 명의 직원들을 고용하고 있습니다. 비록 Core Resources사가 아직 그녀의 후임자의 이름을 대중에게 발표하지 않았고, Ms. Rose의 퇴임이 더 가까워져야 그렇게 할 것 같지만, 몇몇 분석가들은 회사의 차기 리더가 누가 될지를 추측하고 있습니다. 널리 논의되고 있는 한 후보자는 회사의 현 최고 재무 책임자인 Dale Fenny입니다."}]}, {"start": 89, "part": 4, "intro": "", "graphic": false, "speakers": "캐나다식 발음", "audio": "Test02_89-91.mp3", "qs": [{"n": 89, "q": "What does Harford Snow promise to do?", "opts": ["Provide the lowest rates", "Inspect properties at no charge", "Perform a task within a few hours", "Contact customers before arriving"], "ans": 2, "ko": "Harford Snow사는 무엇을 하겠다고 약속하는가?"}, {"n": 90, "q": "According to the speaker, what service is available for an extra fee?", "opts": ["Safety training", "Driveway cleaning", "Equipment repair", "Ice removal"], "ans": 3, "ko": "화자에 따르면, 어떤 서비스가 추가 요금으로 이용 가능한가?"}, {"n": 91, "q": "What information might listeners get on the company's Web site?", "opts": ["Appointment availability", "Consumer reviews", "Discount options", "Refund instructions"], "ans": 1, "ko": "청자들은 회사의 웹사이트에서 어떤 정보를 얻을 수 있는가?"}], "script": [{"sp": "M", "en": "If you're tired of shoveling snow from your driveway or sidewalk, then contact Harford Snow today. For a flat monthly fee, you will never have to worry about doing this again. At Harford, we pride ourselves on our efficiency and reliability, which is why we guarantee that the snow will be removed from your property within four hours after a snowfall ends. If our workers ever arrive late, you will not be charged for that month. And for a small additional fee, we will use salt to get rid of the ice on all your walkways. Visit us at www.harfordsnow.com for a list of the areas that we operate in and over 100 testimonials from satisfied customers.", "ko": "만약 당신이 진입로나 보도의 눈을 치우는 것에 싫증이 났다면, 오늘 Harford Snow사에 연락주세요. 균일한 월간 이용료로, 이 일을 하는 것에 대해 다시는 염려하실 필요가 없을 것입니다. 저희 Harford사에서는 효율성과 신뢰성을 자부하는데, 이것이 바로 저희가 눈이 그친 후 4시간 안에 고객님의 소유지에서 눈이 치워질 것임을 보장하는 이유입니다. 만약 저희 직원들이 늦게 도착하기라도 한다면, 그달은 요금을 청구받지 않으실 것입니다. 그리고 약간의 추가 요금으로, 저희는 소금을 이용하여 고객님의 모든 보도 위에 있는 얼음을 제거해 드릴 것입니다. 저희가 작업하는 지역의 목록과 만족한 고객들로부터의 100개가 넘는 추천 글들을 위해 www.harfordsnow.com을 방문해 주세요."}]}, {"start": 92, "part": 4, "intro": "", "graphic": false, "speakers": "미국식 발음", "audio": "Test02_92-94.mp3", "qs": [{"n": 92, "q": "What is mentioned about The Time Was Then?", "opts": ["It was criticized by some experts.", "It features a famous actress.", "It was only shown in select theaters.", "It has achieved great success."], "ans": 3, "ko": "The Time Was Then에 관해 무엇이 언급되는가?"}, {"n": 93, "q": "Why does the speaker say, \"Gabriela has worked on hundreds of projects\"?", "opts": ["To introduce a recipient", "To explain a decision", "To offer some praise", "To confirm a rumor"], "ans": 2, "ko": "화자는 왜 \"Gabriela는 수백 개의 프로젝트를 작업해 왔습니다\"라고 말하는가?"}, {"n": 94, "q": "What does the speaker say she will do in August?", "opts": ["Promote a recent film", "Start a new project", "Collaborate with a mentor", "Travel for a premiere"], "ans": 1, "ko": "화자는 8월에 무엇을 할 것이라고 말하는가?"}], "script": [{"sp": "W", "en": "Let me begin by thanking the Silver Screen Academy for granting me this Best Young Director Award. While I suspected that The Time Was Then was going to do well, I never guessed it would break international box office records. The incredible team that worked on the film deserves a huge amount of credit. What's more, I want to give a special thanks to Gabriela Hernandez, who taught me everything I know about this art form. Gabriela has worked on hundreds of projects, and I aspire to achieve such a long career. Moving forward, I can only promise to bring an equal amount of passion to my future movies, including Staying Warm, which begins production in August. Again, thank you.", "ko": "저에게 최고의 젊은 감독상을 주신 것에 대해 Silver Screen 협회에 감사 인사를 함으로써 시작하겠습니다. 제가 The Time Was Then이 아마 잘 될거라 생각했지만, 세계 흥행수익 기록들을 깰 것이라고는 전혀 생각하지 못했습니다. 이 영화를 작업한 믿을 수 없이 훌륭한 팀은 엄청난 공로를 인정받을 자격이 있습니다. 더불어, 저는 이 장르에 관해서 제가 아는 모든 것을 가르쳐주신 Gabriela Hernandez께 특별한 감사를 드리고 싶습니다. Gabriela는 수백 개의 프로젝트를 작업해 왔으며, 저는 그러한 오랜 경력을 성취하고 싶은 열망이 있습니다. 앞으로, 제가 유일하게 약속할 수 있는 것은 8월에 제작이 시작되는 Staying Warm을 포함하여, 제 향후 영화들에도 똑같은 열정을 가져갈 것이라는 점입니다. 다시 한번 감사드립니다."}]}, {"start": 95, "part": 4, "intro": "", "graphic": true, "speakers": "호주식 발음", "audio": "Test02_95-97.mp3", "qs": [{"n": 95, "q": "Who is Francine Austen?", "opts": ["A radio program host", "A fashion model", "A magazine editor", "A clothing designer"], "ans": 2, "ko": "Francine Austen은 누구인가?"}, {"n": 96, "q": "Look at the graphic. When was the digital version of Currents launched?", "opts": ["In January", "In February", "In April", "In May"], "ans": 1, "ko": "시각 자료를 보시오. Currents지의 디지털 버전은 언제 출간되었는가?"}, {"n": 97, "q": "What will be discussed during the interview?", "opts": ["A subscription model", "A writing contest", "A clothing trend", "A sponsorship agreement"], "ans": 0, "ko": "인터뷰 동안 무엇이 논의될 것인가?"}], "script": [{"sp": "M", "en": "Stay tuned for Carl Lewis's Daily Business Report. Joining Carl tonight for a rare television interview will be Francine Austen. She is the managing editor of the fashion and design publication Currents. They're going to talk about the online version of the magazine that was launched earlier this year. It has proven to be very successful as the number of new subscribers to Currents increased for two consecutive months after the site became active. This success is attributed to Ms. Austen's development of a subscription model that provides access to the print and digital versions for one low fee. They'll discuss this in depth when we return from a short commercial break.", "ko": "Carl Lewis의 Daily Business Report에 채널을 고정해 주십시오. 오늘 밤 흔치 않은 텔레비전 인터뷰를 위해 Carl과 함께 해주실 분은 Francine Austen입니다. 그녀는 패션 및 디자인 관련 출판물인 Currents지의 편집장입니다. 그들은 올해 초 출간된 잡지의 온라인 버전에 관해 이야기할 것입니다. 사이트가 활성화된 이후 두 달 연속으로 Currents지의 신규 구독자 수가 증가했기 때문에, 온라인 버전은 매우 성공적인 것으로 입증되었습니다. 이 성공은 Ms. Austen이 개발한 하나의 저렴한 비용으로 인쇄 버전과 디지털 버전을 이용할 권리를 제공하는 구독 모델 덕분으로 보입니다. 짧은 광고 방송 후에 그들은 이것에 관해 상세히 논의할 것입니다."}], "gimg": "hk2_t2_g95.jpg"}, {"start": 98, "part": 4, "intro": "", "graphic": true, "speakers": "영국식 발음", "audio": "Test02_98-100.mp3", "qs": [{"n": 98, "q": "What does the speaker plan to do in April?", "opts": ["Start a new job", "Take some tests", "Volunteer at a center", "Register for classes"], "ans": 1, "ko": "화자는 4월에 무엇을 할 계획인가?"}, {"n": 99, "q": "What problem does the speaker mention?", "opts": ["She failed an exam.", "She forgot a prior commitment.", "She missed a workshop.", "She did not meet a deadline."], "ans": 1, "ko": "화자는 무슨 문제를 언급하는가?"}, {"n": 100, "q": "Look at the graphic. Which session will the speaker probably miss?", "opts": ["Online Job Search Resources", "Importance of Networking", "Résumés & Cover Letters", "Preparing for an Interview"], "ans": 2, "ko": "시각 자료를 보시오. 화자는 어느 강의를 놓칠 것 같은가?"}], "script": [{"sp": "W", "en": "Hello. My name is Alice Warren, and I'm registered for the student employment workshop that will be held at the Westwood Employment Center on Saturday. I'm very excited about this because I plan to begin searching for a summer internship in early May, once I've finished my final exams at the end of April. But there's one problem . . . I have to meet with my professor to discuss an assignment that day. Um, it slipped my mind when I signed up for the workshop yesterday. Would it be a problem if I skipped one of the sessions? I would leave at noon and be back just after two. Please call me at 555-4938 to let me know if this is allowed. Thanks.", "ko": "안녕하세요. 제 이름은 Alice Warren이고, 토요일에 Westwood 취업 센터에서 열릴 학생 취업 워크숍에 등록되어 있어요. 전 4월 말에 기말시험이 끝나는 대로 5월 초에 여름 인턴십을 찾아보기 시작할 계획이기 때문에, 이 워크숍을 매우 기대하고 있어요. 그런데 한 가지 문제가 있어요… 그날 저는 과제에 관해 논의하기 위해 저희 교수님과 만나야 해요. 음, 어제 제가 워크숍에 등록할 때 이것을 깜빡 잊어버렸어요. 만약 제가 강의들 중 하나를 빼먹는다면 문제가 될까요? 저는 정오에 떠나서 2시 직후에 돌아올 것 같아요. 555-4938로 제게 전화 주셔서 이것이 허용되는지 알려주세요. 감사합니다."}], "gimg": "hk2_t2_g98.jpg"}]};
